import{_ as a,o as s,c as e,a6 as t}from"./chunks/framework.DtxWasON.js";const k=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/faqs.md","filePath":"mainchain/introduction/faqs.md"}'),n={name:"mainchain/introduction/faqs.md"};function h(l,i,o,p,r,d){return s(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#_1-what-is-unification-mainchain">1. What is Unification Mainchain?</a><ul><li><a href="#_1-1-what-is-the-official-project-website">1.1. What is the official project website?</a></li><li><a href="#_1-2-what-are-the-github-repo-addresses">1.2. What are the Github repo addresses?</a></li></ul></li><li><a href="#_2-where-can-i-find-the-main-api-documents">2. Where can I find the main API documents?</a></li><li><a href="#_3-where-is-the-block-explorer">3. Where is the block explorer?</a></li><li><a href="#_4-where-can-i-get-the-pre-compiled-binaries">4. Where can I get the pre-compiled binaries?</a></li><li><a href="#_5-how-do-i-compile-the-code-from-source">5. How do I compile the code from source?</a></li><li><a href="#_6-what-is-the-currency-used-on-mainchain">6. What is the currency used on Mainchain?</a></li><li><a href="#_7-quick-start-commands">7. Quick start commands</a><ul><li><a href="#_7-1-how-to-get-the-block-height">7.1. How to get the block height?</a></li><li><a href="#_7-2-how-do-i-create-new-wallet-address">7.2. How do I create new wallet address?</a></li><li><a href="#_7-3-how-to-transfer-fund">7.3. How to transfer FUND?</a></li><li><a href="#_7-4-how-do-i-get-all-transactions-related-to-one-wallet-account">7.4. How do I get all transactions related to one wallet/account?</a></li><li><a href="#_7-5-how-do-i-get-the-fund-balance-for-one-wallet-account">7.5. How do I get the FUND balance for one wallet/account?</a></li><li><a href="#_7-6-how-do-i-query-the-total-fund-supply">7.6 How do I query the total FUND supply?</a></li><li><a href="#_7-7-how-do-i-query-the-enterprise-fund-supply-and-what-is-the-significance-of-amount-locked-total">7.7 How do I query the Enterprise FUND supply, and what is the significance of amount/locked/total?</a></li><li><a href="#_7-8-how-do-i-export-dump-backup-a-wallet">7.8. How do I export（dump/backup）a wallet?</a></li><li><a href="#_7-9-how-do-i-import-a-wallet">7.9. How do I import a wallet?</a></li></ul></li></ul></nav><h2 id="_1-what-is-unification-mainchain" tabindex="-1">1. What is Unification Mainchain? <a class="header-anchor" href="#_1-what-is-unification-mainchain" aria-label="Permalink to &quot;1. What is Unification Mainchain?&quot;">​</a></h2><p>Unification is a scalable master blockchain for Enterprise.</p><ol><li>WrkChains can be considered similar to side-chains which allow scaling processing power and cost metrics for enterprises who need an immutable blockchain without being directly on a public blockchain</li><li>Mainchain is the master 100% public blockchain which WrkChains consume FUND to submit their block header hashes to Mainchain for public immutability.</li></ol><p>See <a href="./about-mainchain.html">About Mainchain</a> for further details.</p><h3 id="_1-1-what-is-the-official-project-website" tabindex="-1">1.1. What is the official project website? <a class="header-anchor" href="#_1-1-what-is-the-official-project-website" aria-label="Permalink to &quot;1.1. What is the official project website?&quot;">​</a></h3><p><a href="https://unification.com" target="_blank" rel="noreferrer">https://unification.com</a></p><h3 id="_1-2-what-are-the-github-repo-addresses" tabindex="-1">1.2. What are the Github repo addresses? <a class="header-anchor" href="#_1-2-what-are-the-github-repo-addresses" aria-label="Permalink to &quot;1.2. What are the Github repo addresses?&quot;">​</a></h3><ul><li><a href="https://github.com/unification-com" target="_blank" rel="noreferrer">https://github.com/unification-com</a></li><li>Mainchain repo - <a href="https://github.com/unification-com/mainchain" target="_blank" rel="noreferrer">https://github.com/unification-com/mainchain</a></li></ul><h2 id="_2-where-can-i-find-the-main-api-documents" tabindex="-1">2. Where can I find the main API documents? <a class="header-anchor" href="#_2-where-can-i-find-the-main-api-documents" aria-label="Permalink to &quot;2. Where can I find the main API documents?&quot;">​</a></h2><ul><li><code>und</code> command reference: <a href="./../software/und_cmd/und.html">und commands</a></li><li>Public REST API:<br><strong>MainNet</strong> - <a href="https://rest.unification.io/swagger/" target="_blank" rel="noreferrer">https://rest.unification.io/swagger/</a><br><strong>TestNet</strong> - <a href="https://rest-testnet.unification.io/swagger/" target="_blank" rel="noreferrer">https://rest-testnet.unification.io/swagger/</a></li><li>Public RPC Interface:<br><strong>MainNet</strong> - <a href="https://rpc1.unification.io" target="_blank" rel="noreferrer">https://rpc1.unification.io:443</a><br><strong>TestNet</strong> - <a href="https://rpc-testnet.unification.io" target="_blank" rel="noreferrer">https://rpc-testnet.unification.io:443</a><br> The RPC specification is the same as <a href="https://docs.tendermint.com/master/rpc/" target="_blank" rel="noreferrer">Tendermint</a>.</li></ul><h2 id="_3-where-is-the-block-explorer" tabindex="-1">3. Where is the block explorer? <a class="header-anchor" href="#_3-where-is-the-block-explorer" aria-label="Permalink to &quot;3. Where is the block explorer?&quot;">​</a></h2><ul><li><strong>MainNet</strong> - <a href="https://explorer.unification.io" target="_blank" rel="noreferrer">https://explorer.unification.io</a></li><li><strong>TestNet</strong> - <a href="https://explorer-testnet.unification.io" target="_blank" rel="noreferrer">https://explorer-testnet.unification.io</a></li></ul><h2 id="_4-where-can-i-get-the-pre-compiled-binaries" tabindex="-1">4. Where can I get the pre-compiled binaries? <a class="header-anchor" href="#_4-where-can-i-get-the-pre-compiled-binaries" aria-label="Permalink to &quot;4. Where can I get the pre-compiled binaries?&quot;">​</a></h2><p>Latest compiled binaries available from <a href="https://github.com/unification-com/mainchain/releases" target="_blank" rel="noreferrer">https://github.com/unification-com/mainchain/releases</a></p><ul><li><code>und</code> software has been compiled for Linux x86_64, OSX and Windows. Tested on CentOS, and Ubuntu</li></ul><h2 id="_5-how-do-i-compile-the-code-from-source" tabindex="-1">5. How do I compile the code from source? <a class="header-anchor" href="#_5-how-do-i-compile-the-code-from-source" aria-label="Permalink to &quot;5. How do I compile the code from source?&quot;">​</a></h2><p>Build instructions are <a href="./../software/installation.html#building-from-source">available here</a></p><p>This will build and install the <code>und</code> binary into <code>$GOPATH/bin</code></p><h2 id="_6-what-is-the-currency-used-on-mainchain" tabindex="-1">6. What is the currency used on Mainchain? <a class="header-anchor" href="#_6-what-is-the-currency-used-on-mainchain" aria-label="Permalink to &quot;6. What is the currency used on Mainchain?&quot;">​</a></h2><p>The currency used on Mainchain is <strong>FUND</strong>. However, the native on-chain coin denomination (on MainNet, TestNet and DevNet) is <strong><code>nund</code></strong>, or &quot;Nano Unification Denomination&quot;, such that <strong>1,000,000,000 nund == 1 FUND</strong>.</p><p>All transactions, fees and stakes are defined and paid for in <code>nund</code>. For example, if you need to send <strong>1 FUND</strong> to your friend, you will need to set your Tx to send <code>1000000000nund</code>.</p><p>See &quot;<a href="./denomination.html">Native Coin Denomination <code>nund</code></a>&quot; for more details.</p><h2 id="_7-quick-start-commands" tabindex="-1">7. Quick start commands <a class="header-anchor" href="#_7-quick-start-commands" aria-label="Permalink to &quot;7. Quick start commands&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>PROTOCOL</code> in the <code>--node</code> flags below may be <code>tcp</code>, <code>http</code> or <code>https</code>, depending on the configuration of the full node being queried/used for broadcast.</p></div><h3 id="_7-1-how-to-get-the-block-height" tabindex="-1">7.1. How to get the block height? <a class="header-anchor" href="#_7-1-how-to-get-the-block-height" aria-label="Permalink to &quot;7.1. How to get the block height?&quot;">​</a></h3><p>Several methods available:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PROTOCOL://NODE:PORT</span></span></code></pre></div><p><strong>TestNet Example</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-TestNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc-testnet.unification.io:443</span></span></code></pre></div><p><strong>MainNet Example</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-MainNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc1.unification.io:443</span></span></code></pre></div><p>A JSON or text object is returned, and latest height available from <code>sync_info.latest_block_height</code></p><p>RPC equivalent on TestNet: <a href="https://rpc-testnet.unification.io:443/abci_info" target="_blank" rel="noreferrer">https://rpc-testnet.unification.io:443/abci_info</a> and MainNet: <a href="https://rpc1.unification.io:443/abci_info" target="_blank" rel="noreferrer">https://rpc1.unification.io:443/abci_info</a></p><p><code>und query block</code> can also be used:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> block</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=PROTOCOL://NODE:PORT</span></span></code></pre></div><p>Will return the latest block info if no height is passed to the query.</p><p><strong>TestNet</strong> example, using the public RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> block</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-TestNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc-testnet.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --trust-node=true</span></span></code></pre></div><p><strong>MainNet</strong> example, using the public RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> block</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-MainNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc1.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --trust-node=true</span></span></code></pre></div><p>Finally, a <code>curl</code> request can be made to the RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://rpc-testnet.unification.io/status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://rpc1.unification.io/status</span></span></code></pre></div><h3 id="_7-2-how-do-i-create-new-wallet-address" tabindex="-1">7.2. How do I create new wallet address? <a class="header-anchor" href="#_7-2-how-do-i-create-new-wallet-address" aria-label="Permalink to &quot;7.2. How do I create new wallet address?&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ACC_NAME</span></span></code></pre></div><p><code>ACC_NAME</code> is whatever ASCII identifier you want to give the account/wallet/address, and is used to reference the account when creating/signing Txs.</p><p>The command will output pertinent information - name (as passed in the command), wallet address, public key and recovery mnemonic in either JSON or text format.</p><p>Example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> some_new_account</span></span></code></pre></div><p>Run <code>und keys add --help</code> or see the <a href="./../software/und_cmd/und_keys_add.html">und keys add</a> reference for details on flags/command options etc.</p><h3 id="_7-3-how-to-transfer-fund" tabindex="-1">7.3. How to transfer FUND? <a class="header-anchor" href="#_7-3-how-to-transfer-fund" aria-label="Permalink to &quot;7.3. How to transfer FUND?&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [from_key_or_address] [to_address] [amount] --chain-id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">CHAIN_ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PROTOCOL://NODE_IP:PORT</span></span></code></pre></div><p>Amount is <code>nund</code> - &quot;Nano Unification Denomination&quot;, such that <strong>1,000,000,000 nund == 1 FUND</strong>. See <a href="./denomination.html">denomination</a>.</p><p>Example to send <strong>10 FUND</strong> from <code>my_account</code> account (see Q7.2 about account names) on <strong>TestNet</strong>, using the public RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und1nkhnc5e8pvph4phv93k0lkscc7yf5eh9kas5f6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10000000000nund</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=FUND-TestNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --node=https://rpc-testnet.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas=auto</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas-adjustment=1.5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas-prices=25.0nund</span></span></code></pre></div><p>The same example, using <strong>MainNet</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und1nkhnc5e8pvph4phv93k0lkscc7yf5eh9kas5f6</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10000000000nund</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=FUND-MainNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --node=https://rpc1.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas=auto</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas-adjustment=1.5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas-prices=25.0nund</span></span></code></pre></div><p>See <a href="./../software/und_cmd/und_tx_bank_send.html">und tx bank send</a> and <a href="./fees-and-gas.html">fees and gas</a> for more in-depth information.</p><h3 id="_7-4-how-do-i-get-all-transactions-related-to-one-wallet-account" tabindex="-1">7.4. How do I get all transactions related to one wallet/account? <a class="header-anchor" href="#_7-4-how-do-i-get-all-transactions-related-to-one-wallet-account" aria-label="Permalink to &quot;7.4. How do I get all transactions related to one wallet/account?&quot;">​</a></h3><p><code>und query txs</code> can be used to query all transactions. Passing the <code>--events</code> flag will allow you to filter indexed events by a particular account. Data is returned paginated.</p><p><strong>TestNet</strong> example to get Txs sent by <code>und17jv7rerc2e3undqumpf32a3xs9jc0kjk4z2car</code>, using the public RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> txs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --events</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;message.sender=und17jv7rerc2e3undqumpf32a3xs9jc0kjk4z2car&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=FUND-TestNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --node=https://rpc-testnet.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --page</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 30</span></span></code></pre></div><p>The same query, using <strong>MainNet</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> txs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --events</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;message.sender=und17jv7rerc2e3undqumpf32a3xs9jc0kjk4z2car&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=FUND-MainNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --node=https://rpc1.unification.io:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --page</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 30</span></span></code></pre></div><p>The <code>--events</code> flag can contain any <code>{eventType}.{eventAttribute}={value}</code> type query. For example <code>--events &#39;transfer.recipient=und17jv7rerc2e3undqumpf32a3xs9jc0kjk4z2car&#39;</code> will return queries relating to transfers into the account. See <a href="./../software/und_cmd/und_query_txs.html">und query txs</a> for further information.</p><h3 id="_7-5-how-do-i-get-the-fund-balance-for-one-wallet-account" tabindex="-1">7.5. How do I get the FUND balance for one wallet/account? <a class="header-anchor" href="#_7-5-how-do-i-get-the-fund-balance-for-one-wallet-account" aria-label="Permalink to &quot;7.5. How do I get the FUND balance for one wallet/account?&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [address] [flags] --chain-id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">CHAIN_ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">PROTOCOL://NODE_IP:PORT</span></span></code></pre></div><p>Example on <strong>TestNet</strong>, using the public RPC node:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und1eyn7s6qz2gcnfld0uskwxedyunpgjhlcjhvul9</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-TestNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc-testnet.unification.io:443</span></span></code></pre></div><p>Using <strong>MainNet</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> und1eyn7s6qz2gcnfld0uskwxedyunpgjhlcjhvul9</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=FUND-MainNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=https://rpc1.unification.io:443</span></span></code></pre></div><p>Will return a JSON or text object (depending on options passed). <code>account.value.coins</code> in the returned result shows the amount of <code>nund</code>. The above example (currently) shows the account has <strong>10000000000 nund (10 FUND)</strong> on TestNet.</p><h3 id="_7-6-how-do-i-query-the-total-fund-supply" tabindex="-1">7.6 How do I query the total FUND supply? <a class="header-anchor" href="#_7-6-how-do-i-query-the-total-fund-supply" aria-label="Permalink to &quot;7.6 How do I query the total FUND supply?&quot;">​</a></h3><p>The command</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=PROTOCOL://NODE_IP:PORT</span></span></code></pre></div><p>Will return:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120010263000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  denom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nund</span></span></code></pre></div><p>The equivalent REST query is at the enpoint <code>/mainchain/enterprise/v1/supply</code> - for example:</p><ul><li>TestNet public REST server <a href="https://rest-testnet.unification.io/mainchain/enterprise/v1/supply" target="_blank" rel="noreferrer">https://rest-testnet.unification.io/mainchain/enterprise/v1/supply</a></li><li>MainNet public REST server <a href="https://rest.unification.io/mainchain/enterprise/v1/supply" target="_blank" rel="noreferrer">https://rest.unification.io/mainchain/enterprise/v1/supply</a></li></ul><div class="danger custom-block"><p class="custom-block-title">IMPORTANT!!!</p><p>the <code>/mainchain/enterprise/v1/supply</code> endpoint <strong>MUST</strong> be used instead of <code>/cosmos/bank/v1beta1/supply</code> to get true total supply available for general use, i.e. with locked eFUND removed from total</p></div><h3 id="_7-7-how-do-i-query-the-enterprise-fund-supply-and-what-is-the-significance-of-amount-locked-total" tabindex="-1">7.7 How do I query the Enterprise FUND supply, and what is the significance of amount/locked/total? <a class="header-anchor" href="#_7-7-how-do-i-query-the-enterprise-fund-supply-and-what-is-the-significance-of-amount-locked-total" aria-label="Permalink to &quot;7.7 How do I query the Enterprise FUND supply, and what is the significance of amount/locked/total?&quot;">​</a></h3><p>The command</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enterprise</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ent-supply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=PROTOCOL://NODE_IP:PORT</span></span></code></pre></div><p>Will return the complete supply information. Three quantity values are returned:</p><ol><li><strong>amount</strong>: Liquid FUND in active circulation, and the actual circulating total supply which is available and can be used for FUND transfers, staking, Tx fees etc. It is the <strong>locked</strong> amount subtracted from <strong>total</strong>. <em>This is the important value when processing any calculations dependent on FUND circulation/total supply of FUND etc.</em></li><li><strong>locked</strong>: Total FUND locked through Enterprise purchases. This FUND is only available specifically to pay WRKChain/BEACON fees and <strong>cannot</strong> be used for transfers, staking/delegation or any other transactions. <em>Locked FUND only enters the active circulation supply once it has been used to pay for WRKChain/BEACON fees. Until then, it is considered &quot;dormant&quot;, and not part of the circulating total supply</em></li><li><strong>total</strong>: The total amount of FUND currently known on the chain, including any Enterprise <strong>locked</strong> FUND. This is for informational purposes only and should not be used for any &quot;circulating/total supply&quot; calculations.</li></ol><p>The <strong>amount</strong> value is the important value regarding total supply <em>currently in active circulation</em>, and is the information that should be used to represent any &quot;total supply/circulation&quot; values for example in block explorers, wallets, exchanges etc.</p><p>Consider the following <code>und query supply</code> result:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">supply</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120010263000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  denom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nund</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  locked</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;89737000000000&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  total</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;120100000000000000&quot;</span></span></code></pre></div><p>In the above example, the active circulating supply - usable for transfers and standard transactions etc. - is currently 120,010,263 FUND. 89,737 FUND is currently locked, and can only be used for paying for WRKChain/BEACON fees - it is &quot;dormant&quot; and <em>cannot be used for any other purpose until it has been used to pay for WRKChain/BEACON fees</em>. Finally, the total amount of FUND known on the chain is 120,100,000 FUND, and is the equivalent of 120,010,263 + 89,737.</p><p>See <a href="./../software/und_cmd/und_query_supply.html">und query supply</a> for more details on command flags and parameters, and <a href="./total-supply.html">total supply</a> for more information on the query results and FUND conversion.</p><h3 id="_7-8-how-do-i-export-dump-backup-a-wallet" tabindex="-1">7.8. How do I export（dump/backup）a wallet? <a class="header-anchor" href="#_7-8-how-do-i-export-dump-backup-a-wallet" aria-label="Permalink to &quot;7.8. How do I export（dump/backup）a wallet?&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> export</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> some_new_account</span></span></code></pre></div><p>will export an account private key in ASCII-armored encrypted format.</p><h3 id="_7-9-how-do-i-import-a-wallet" tabindex="-1">7.9. How do I import a wallet? <a class="header-anchor" href="#_7-9-how-do-i-import-a-wallet" aria-label="Permalink to &quot;7.9. How do I import a wallet?&quot;">​</a></h3><p>There are a couple of methods, depending on the import format. If the bip39 mnemonic is available, then:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> some_new_account</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recover</span></span></code></pre></div><p>Will prompt you for the bip39 mnemonic. See <a href="./../software/und_cmd/und_keys_add.html">und keys add</a></p><p>If the private key has been exported (e.g. via <code>und keys export</code>), then the <code>und keys import</code> command can be used:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ACC_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> KEYFILE</span></span></code></pre></div><p>See <a href="./../software/und_cmd/und_keys_import.html">und keys import</a></p>`,102)])])}const u=a(n,[["render",h]]);export{k as __pageData,u as default};
